INSERT INTO peliculas (titulo, director, genero, año, sipnosis) VALUES ('El Caballero Oscuro', 'Christopher Nolan', 'Acción/Crimen', 2008, 'Batman se propone destruir el crimen organizado en Gotham, enfrentándose a The Joker...');
