INSERT INTO peliculas (titulo, director, genero, año, sipnosis) VALUES ('Inception', 'Christopher Nolan', 'Sci-Fi', 2010, 'Un ladrón que roba secretos corporativos a través del uso de la tecnología de compartir sueños.');
INSERT INTO peliculas (titulo, director, genero, año, sipnosis) VALUES ('Interstellar', 'Christopher Nolan', 'Sci-Fi', 2014, 'Un equipo de exploradores viaja a través de un agujero de gusano en el espacio en un intento por garantizar la supervivencia de la humanidad.');
